INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Back_Flyes_-_With_Bands','Back Flyes - With Bands','hombros',ARRAY['espalda media','tríceps'],'bandas elásticas','strength',ARRAY['Run a band around a stationary post like that of a squat rack.','Grab the band by the handles and stand back so that the tension in the band rises.','Extend and lift the arms straight in front of you. Tip: Your arms should be straight and parallel to the floor while perpendicular to your torso. Your feet should be firmly planted on the floor spread at shoulder width. This will be your starting position.','As you exhale, move your arms to the sides and back. Keep your arms extended and parallel to the floor. Continue the movement until the arms are extended to your sides.','After a pause, go back to the original position as you inhale.','Repeat for the recommended amount of repetitions.'],'Run a band around a stationary post like that of a squat rack. Grab the band by the handles and stand back so that the tension in the band rises. Extend and lift the arms straight in front of you. Tip: Your arms should be straight and parallel to the floor while perpendicular to your torso. Your feet should be firmly planted on the floor spread at shoulder width. This will be your starting position. As you exhale, move your arms to the sides and back. Keep your arms extended and parallel to the floor. Continue the movement until the arms are extended to your sides. After a pause, go back to the original position as you inhale. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Back_Flyes_-_With_Bands/0.jpg','exercisedb',true),('Backward_Drag','Backward Drag','cuádriceps',ARRAY['pantorrillas','antebrazos','glúteos','isquiotibiales','espalda baja'],'otro','strongman',ARRAY['Load a sled with the desired weight, attaching a rope or straps to the sled that you can hold onto.','Begin the exercise by moving backwards for a given distance. Leaning back, extend through the legs for short steps to move as quickly as possible.'],'Load a sled with the desired weight, attaching a rope or straps to the sled that you can hold onto. Begin the exercise by moving backwards for a given distance. Leaning back, extend through the legs for short steps to move as quickly as possible.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Backward_Drag/0.jpg','exercisedb',true),('Backward_Medicine_Ball_Throw','Backward Medicine Ball Throw','hombros',ARRAY[]::text[],'balón medicinal','plyometrics',ARRAY['This exercise is best done with a partner. If you lack a partner, the ball can be thrown and retrieved or thrown against a wall.','Begin standing a few meters in front of your partner, both facing the same direction. Begin holding the ball between your legs.','Squat down and then forcefully reverse direction, coming to full extension and you toss the ball over your head to your partner.','Your partner can then roll the ball back to you. Repeat for the desired number of repetitions.'],'This exercise is best done with a partner. If you lack a partner, the ball can be thrown and retrieved or thrown against a wall. Begin standing a few meters in front of your partner, both facing the same direction. Begin holding the ball between your legs. Squat down and then forcefully reverse direction, coming to full extension and you toss the ball over your head to your partner. Your partner can then roll the ball back to you. Repeat for the desired number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Backward_Medicine_Ball_Throw/0.jpg','exercisedb',true),('Balance_Board','Balance Board','pantorrillas',ARRAY['isquiotibiales','cuádriceps'],'otro','strength',ARRAY['Place a balance board in front of you.','Stand up on it and try to balance yourself.','Hold the balance for as long as desired.'],'Place a balance board in front of you. Stand up on it and try to balance yourself. Hold the balance for as long as desired.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Balance_Board/0.jpg','exercisedb',true),('Ball_Leg_Curl','Ball Leg Curl','isquiotibiales',ARRAY['pantorrillas','glúteos'],'pelota de ejercicio','strength',ARRAY['Begin on the floor laying on your back with your feet on top of the ball.','Position the ball so that when your legs are extended your ankles are on top of the ball. This will be your starting position.','Raise your hips off of the ground, keeping your weight on the shoulder blades and your feet.','Flex the knees, pulling the ball as close to you as you can, contracting the hamstrings.','After a brief pause, return to the starting position.'],'Begin on the floor laying on your back with your feet on top of the ball. Position the ball so that when your legs are extended your ankles are on top of the ball. This will be your starting position. Raise your hips off of the ground, keeping your weight on the shoulder blades and your feet. Flex the knees, pulling the ball as close to you as you can, contracting the hamstrings. After a brief pause, return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Ball_Leg_Curl/0.jpg','exercisedb',true),('Band_Assisted_Pull-Up','Band Assisted Pull-Up','dorsales',ARRAY['abdominales','antebrazos','espalda media'],'otro','strength',ARRAY['Choke the band around the center of the pullup bar. You can use different bands to provide varying levels of assistance.','Pull the end of the band down, and place one bent knee into the loop, ensuring it won''''t slip out. Take a medium to wide grip on the bar. This will be your starting position.','Pull yourself upward by contracting the lats as you flex the elbow. The elbow should be driven to your side. Pull to the front, attempting to get your chin over the bar. Avoid swinging or jerking movements.','After a brief pause, return to the starting position.'],'Choke the band around the center of the pullup bar. You can use different bands to provide varying levels of assistance. Pull the end of the band down, and place one bent knee into the loop, ensuring it won''t slip out. Take a medium to wide grip on the bar. This will be your starting position. Pull yourself upward by contracting the lats as you flex the elbow. The elbow should be driven to your side. Pull to the front, attempting to get your chin over the bar. Avoid swinging or jerking movements. After a brief pause, return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Assisted_Pull-Up/0.jpg','exercisedb',true),('Band_Good_Morning','Band Good Morning','isquiotibiales',ARRAY['glúteos','espalda baja'],'bandas elásticas','powerlifting',ARRAY['Using a 41 inch band, stand on one end, spreading your feet a small amount. Bend at the hips to loop the end of the band behind your neck. This will be your starting position.','Keeping your legs straight, extend through the hips to come to a near vertical position.','Ensure that you do not round your back as you go down back to the starting position.'],'Using a 41 inch band, stand on one end, spreading your feet a small amount. Bend at the hips to loop the end of the band behind your neck. This will be your starting position. Keeping your legs straight, extend through the hips to come to a near vertical position. Ensure that you do not round your back as you go down back to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Good_Morning/0.jpg','exercisedb',true),('Band_Good_Morning_Pull_Through','Band Good Morning (Pull Through)','isquiotibiales',ARRAY['glúteos','espalda baja'],'bandas elásticas','powerlifting',ARRAY['Loop the band around a post. Standing a little ways away, loop the opposite end around the neck. Your hands can help hold the band in position.','Begin by bending at the hips, getting your butt back as far as possible. Keep your back flat and bend forward to about 90 degrees. Your knees should be only slightly bent.','Return to the starting position be driving through with the hips to come back to a standing position.'],'Loop the band around a post. Standing a little ways away, loop the opposite end around the neck. Your hands can help hold the band in position. Begin by bending at the hips, getting your butt back as far as possible. Keep your back flat and bend forward to about 90 degrees. Your knees should be only slightly bent. Return to the starting position be driving through with the hips to come back to a standing position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Good_Morning_Pull_Through/0.jpg','exercisedb',true),('Band_Hip_Adductions','Band Hip Adductions','aductores',ARRAY[]::text[],'bandas elásticas','strength',ARRAY['Anchor a band around a solid post or other object.','Stand with your left side to the post, and put your right foot through the band, getting it around the ankle.','Stand up straight and hold onto the post if needed. This will be your starting position.','Keeping the knee straight, raise your right legs out to the side as far as you can.','Return to the starting position and repeat for the desired rep count.','Switch sides.'],'Anchor a band around a solid post or other object. Stand with your left side to the post, and put your right foot through the band, getting it around the ankle. Stand up straight and hold onto the post if needed. This will be your starting position. Keeping the knee straight, raise your right legs out to the side as far as you can. Return to the starting position and repeat for the desired rep count. Switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Hip_Adductions/0.jpg','exercisedb',true),('Band_Pull_Apart','Band Pull Apart','hombros',ARRAY['espalda media','trapecios'],'bandas elásticas','strength',ARRAY['Begin with your arms extended straight out in front of you, holding the band with both hands.','Initiate the movement by performing a reverse fly motion, moving your hands out laterally to your sides.','Keep your elbows extended as you perform the movement, bringing the band to your chest. Ensure that you keep your shoulders back during the exercise.','Pause as you complete the movement, returning to the starting position under control.'],'Begin with your arms extended straight out in front of you, holding the band with both hands. Initiate the movement by performing a reverse fly motion, moving your hands out laterally to your sides. Keep your elbows extended as you perform the movement, bringing the band to your chest. Ensure that you keep your shoulders back during the exercise. Pause as you complete the movement, returning to the starting position under control.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Pull_Apart/0.jpg','exercisedb',true);